<script>
    import { Link } from "svelte-routing";
    import RotatingSphere from "./main-home_anime.svelte";
    import ContentCarousel from "../../components/ContentCarousel.svelte";
    import allContent from "../../data/content.json";

    const mathContent = allContent.filter(item => item.tags.includes("#math"));
    const scienceContent = allContent.filter(item => item.tags.includes("#science"));
    const csContent = allContent.filter(item => item.tags.includes("#cs"));
    const latestContent = [...allContent]
        .sort((a, b) => new Date(b.date) - new Date(a.date))
        .slice(0, 3);
    const interactiveContent = allContent.filter((item) => item.jsFile);
    const allCategories = [...new Set(allContent.flatMap((item) => item.tags))].sort((a, b) => a.localeCompare(b, "ko"));
    const topics = [
        { id: "Math", title: "수학", body: "정의와 구조를 중심으로 곡선, 기하, 해석 개념을 읽는 컬렉션", to: "/mathpage" },
        { id: "Science", title: "자연 과학", body: "물리, 생물, 화학의 핵심 현상을 짧은 글로 빠르게 탐색하는 섹션", to: "/sciencepage" },
        { id: "CS", title: "컴퓨터 과학", body: "설명형 글과 실험형 콘텐츠를 같이 배치한 탐색형 페이지", to: "/cspage" }
    ];

    let isCategoryOpen = false;
    let selectedCategory = "";
    let showInteractiveContent = false;

    $: filteredContent = selectedCategory
        ? allContent.filter((item) => item.tags.includes(selectedCategory))
        : [];

    function toggleCategoryMenu() {
        isCategoryOpen = !isCategoryOpen;
    }

    function selectCategory(category) {
        selectedCategory = category;
        isCategoryOpen = false;
    }

    function clearCategory() {
        selectedCategory = "";
    }

    function toggleInteractiveContent() {
        showInteractiveContent = !showInteractiveContent;
    }
</script>

<div class="page-shell home-page">
    <section class="hero-stage">
        <div class="hero-visual">
            <div class="hero-glow"></div>
            <RotatingSphere />
        </div>
    </section>

    <section class="overview-grid">
        <div class="overview-card soft-card stat-panel">
            <span class="stat-number">{allContent.length}</span>
            <p>전체 아카이브 항목</p>
        </div>
        <div class="overview-card soft-card stat-panel">
            <span class="stat-number">{allCategories.length}</span>
            <button class="category-toggle" type="button" on:click={toggleCategoryMenu}>카테고리</button>
            {#if isCategoryOpen}
                <div class="category-menu">
                    {#each allCategories as category}
                        <button type="button" class="category-option" on:click={() => selectCategory(category)}>
                            {category}
                        </button>
                    {/each}
                </div>
            {/if}
        </div>
        <div class="overview-card soft-card stat-panel">
            <span class="stat-number">{interactiveContent.length}</span>
            <button class="category-toggle" type="button" on:click={toggleInteractiveContent}>실험형 인터랙션</button>
        </div>
    </section>

    {#if selectedCategory}
        <section class="filtered-section">
            <div class="section-heading">
                <div>
                    <span class="section-kicker">Category</span>
                    <h2>{selectedCategory}</h2>
                </div>
                <button class="clear-filter" type="button" on:click={clearCategory}>전체 보기</button>
            </div>
            <div class="featured-grid">
                {#each filteredContent as item}
                    <Link to={`/content/${item.id}`} class="feature-card soft-card">
                        <span class="feature-date">{item.date}</span>
                        <h2>{item.title}</h2>
                        <p>{item.description}</p>
                        <span class="feature-tags">#{item.tags.length}</span>
                    </Link>
                {/each}
            </div>
        </section>
    {/if}

    {#if showInteractiveContent}
        <section class="filtered-section">
            <div class="section-heading">
                <div>
                    <span class="section-kicker">Collection</span>
                    <h2>실험형 인터랙션</h2>
                </div>
                <button class="clear-filter" type="button" on:click={toggleInteractiveContent}>닫기</button>
            </div>
            <div class="featured-grid">
                {#each interactiveContent as item}
                    <Link to={`/content/${item.id}`} class="feature-card soft-card">
                        <span class="feature-date">{item.date}</span>
                        <h2>{item.title}</h2>
                        <p>{item.description}</p>
                        <span class="feature-tags">#{item.tags.length}</span>
                    </Link>
                {/each}
            </div>
        </section>
    {/if}

    <section class="topic-strip">
        {#each topics as topic}
            <Link class="topic-card slide-panel" to={topic.to}>
                <span class="topic-id">{topic.id}</span>
                <h2>{topic.title}</h2>
                <p>{topic.body}</p>
                <span class="topic-link">열기</span>
            </Link>
        {/each}
    </section>

    <section class="featured-section">
        <div class="section-heading">
            <div>
                <span class="section-kicker">Collection</span>
                <h2>최근 기록</h2>
            </div>
        </div>
        <div class="featured-grid">
            {#each latestContent as item}
                <Link to={`/content/${item.id}`} class="feature-card soft-card">
                    <span class="feature-date">{item.date}</span>
                    <h2>{item.title}</h2>
                    <p>{item.description}</p>
                    <span class="feature-tags">#{item.tags.length}</span>
                </Link>
            {/each}
        </div>
    </section>

    <section class="carousel-container">
        <ContentCarousel
            title="수학"
            contentItems={mathContent}
        />
    </section>
    <section class="carousel-container">
        <ContentCarousel
            title="자연 과학"
            contentItems={scienceContent}
        />
    </section>
    <section class="carousel-container">
        <ContentCarousel
            title="컴퓨터 과학"
            contentItems={csContent}
        />
    </section>
</div>

