<script>
    import { onMount } from "svelte";
    import { Link, navigate } from "svelte-routing";
    import allContent from "../data/content.json";

    let isOpen = false;
    let isSearchOpen = false;
    let searchTerm = "";
    let searchPanel;
    let searchInput;

    const navItems = [
        { label: "수학", to: "/mathpage" },
        { label: "자연 과학", to: "/sciencepage" },
        { label: "컴퓨터 과학", to: "/cspage" }
    ];

    $: quickResults = allContent
        .filter((item) => {
            const keyword = searchTerm.trim().toLowerCase();
            if (!keyword) {
                return true;
            }

            const haystack = `${item.title} ${item.description} ${item.tags.join(" ")}`.toLowerCase();
            return haystack.includes(keyword);
        })
        .slice(0, 4);

    function toggleMenu() {
        isOpen = !isOpen;
    }

    function toggleSearch() {
        isSearchOpen = !isSearchOpen;

        if (isSearchOpen) {
            isOpen = false;
            setTimeout(() => searchInput && searchInput.focus(), 0);
        }
    }

    function closeSearch() {
        isSearchOpen = false;
        searchTerm = "";
    }

    function goToContent(id) {
        closeSearch();
        navigate(`/content/${id}`);
    }

    function handleClickOutside(event) {
        if (isSearchOpen && searchPanel && !searchPanel.contains(event.target)) {
            closeSearch();
        }
    }

    function stopPropagation() {}

    onMount(() => {
        window.addEventListener("click", handleClickOutside);

        return () => {
            window.removeEventListener("click", handleClickOutside);
        };
    });
</script>

<header class="site-header">
    <div class="nav-shell">
        <nav class="navbar">
            <div class="brand-block">
                <Link to="/" class="brand-mark">WebLab</Link>
                <p class="brand-copy">Learning archive</p>
            </div>

            <button class="hamburger" type="button" on:click={toggleMenu} aria-label="Toggle menu" aria-expanded={isOpen}>
                <span></span>
                <span></span>
                <span></span>
            </button>

            <div class:nav-menu={true} class:open={isOpen}>
                {#each navItems as item}
                    <Link to={item.to} class="nav-link">{item.label}</Link>
                {/each}

                <button class="search-trigger" type="button" on:click|stopPropagation={toggleSearch} aria-label="콘텐츠 검색">
                    Search
                </button>
            </div>
        </nav>

        {#if isSearchOpen}
            <div class="search-panel soft-card" bind:this={searchPanel} on:click|stopPropagation on:keydown={stopPropagation}>
                <div class="search-header">
                    <p>빠른 탐색</p>
                    <button type="button" class="close-button" on:click={closeSearch} aria-label="검색 닫기">닫기</button>
                </div>

                <input
                    bind:this={searchInput}
                    bind:value={searchTerm}
                    class="search-input"
                    type="text"
                    placeholder="제목, 설명, 태그로 검색"
                    aria-label="Search content"
                >

                <div class="search-results">
                    {#each quickResults as item}
                        <button class="result-card" type="button" on:click={() => goToContent(item.id)}>
                            <span class="result-title">{item.title}</span>
                            <span class="result-meta">{item.tags.slice(0, 3).join(" ")}</span>
                        </button>
                    {/each}

                    {#if quickResults.length === 0}
                        <p class="empty-state">일치하는 콘텐츠가 없습니다.</p>
                    {/if}
                </div>
            </div>
        {/if}
    </div>
</header>

