<script>
  import { onMount } from "svelte";

  let container;
  let canvas;

  onMount(() => {
    const ctx = canvas.getContext("2d");
    const offscreen = document.createElement("canvas");
    const offscreenCtx = offscreen.getContext("2d");

    let animationFrame;
    let width = 0;
    let height = 0;
    let particles = [];
    let ambientParticles = [];
    let rings = [];
    let dpr = 1;

    function randomRange(min, max) {
      return Math.random() * (max - min) + min;
    }

    function resizeCanvas() {
      width = container.clientWidth;
      height = container.clientHeight;
      dpr = Math.min(window.devicePixelRatio || 1, 2);

      canvas.width = width * dpr;
      canvas.height = height * dpr;
      canvas.style.width = `${width}px`;
      canvas.style.height = `${height}px`;
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);

      offscreen.width = width;
      offscreen.height = height;

      rebuildTargets();
    }

    function rebuildTargets() {
      offscreenCtx.clearRect(0, 0, width, height);

      const fontSize = Math.max(64, Math.min(width * 0.18, 156));
      offscreenCtx.fillStyle = "#000";
      offscreenCtx.textAlign = "center";
      offscreenCtx.textBaseline = "middle";
      offscreenCtx.font = `800 ${fontSize}px "SF Pro Display", "Helvetica Neue", sans-serif`;
      offscreenCtx.fillText("WebLab", width / 2, height / 2);

      const imageData = offscreenCtx.getImageData(0, 0, width, height).data;
      const gap = width < 640 ? 5 : 6;
      const targets = [];

      for (let y = 0; y < height; y += gap) {
        for (let x = 0; x < width; x += gap) {
          const alpha = imageData[(y * width + x) * 4 + 3];
          if (alpha > 160) {
            targets.push({ x, y });
          }
        }
      }

      particles = targets.map((target, index) => {
        const existing = particles[index];
        return existing
          ? {
              ...existing,
              tx: target.x,
              ty: target.y
            }
          : {
              x: randomRange(0, width),
              y: randomRange(0, height),
              tx: target.x,
              ty: target.y,
              vx: randomRange(-1.5, 1.5),
              vy: randomRange(-1.5, 1.5),
              size: randomRange(1.2, 2.8),
              twinkle: randomRange(0, Math.PI * 2),
              drift: randomRange(0.006, 0.018)
            };
      });

      ambientParticles = Array.from({ length: Math.max(50, Math.floor(width * 0.08)) }, () => ({
        x: randomRange(0, width),
        y: randomRange(0, height),
        size: randomRange(0.8, 1.8),
        alpha: randomRange(0.18, 0.55),
        speed: randomRange(0.05, 0.2)
      }));
    }

    function burstAt(clientX, clientY) {
      const rect = canvas.getBoundingClientRect();
      const cx = clientX - rect.left;
      const cy = clientY - rect.top;
      const radius = Math.min(width, height) * 0.28;

      rings.push({ x: cx, y: cy, radius: 8, alpha: 0.35 });

      particles.forEach((particle) => {
        const dx = particle.x - cx;
        const dy = particle.y - cy;
        const distance = Math.hypot(dx, dy) || 0.001;

        if (distance < radius) {
          const force = (1 - distance / radius) * 12;
          particle.vx += (dx / distance) * force;
          particle.vy += (dy / distance) * force;
        }
      });
    }

    function drawBackground() {
      const gradient = ctx.createLinearGradient(0, 0, 0, height);
      gradient.addColorStop(0, "rgba(10, 18, 36, 0.92)");
      gradient.addColorStop(0.48, "rgba(15, 23, 42, 0.98)");
      gradient.addColorStop(1, "rgba(8, 15, 30, 1)");
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, width, height);

      const glow = ctx.createRadialGradient(width / 2, height / 2, 10, width / 2, height / 2, width * 0.42);
      glow.addColorStop(0, "rgba(56, 189, 248, 0.16)");
      glow.addColorStop(0.45, "rgba(10, 132, 255, 0.08)");
      glow.addColorStop(1, "rgba(10, 132, 255, 0)");
      ctx.fillStyle = glow;
      ctx.fillRect(0, 0, width, height);

      ambientParticles.forEach((particle) => {
        particle.y += particle.speed;
        if (particle.y > height + 10) {
          particle.y = -10;
          particle.x = randomRange(0, width);
        }

        ctx.beginPath();
        ctx.fillStyle = `rgba(191, 219, 254, ${particle.alpha})`;
        ctx.arc(particle.x, particle.y, particle.size, 0, Math.PI * 2);
        ctx.fill();
      });
    }

    function animate() {
      animationFrame = requestAnimationFrame(animate);
      drawBackground();

      particles.forEach((particle) => {
        const dx = particle.tx - particle.x;
        const dy = particle.ty - particle.y;

        particle.vx += dx * 0.013;
        particle.vy += dy * 0.013;
        particle.vx *= 0.86;
        particle.vy *= 0.86;
        particle.x += particle.vx;
        particle.y += particle.vy;
        particle.twinkle += particle.drift;

        const alpha = 0.5 + Math.sin(particle.twinkle) * 0.24;
        ctx.beginPath();
        ctx.fillStyle = `rgba(255, 255, 255, ${alpha + 0.18})`;
        ctx.shadowBlur = 24;
        ctx.shadowColor = "rgba(96, 165, 250, 0.6)";
        ctx.arc(particle.x, particle.y, particle.size, 0, Math.PI * 2);
        ctx.fill();
      });

      ctx.shadowBlur = 0;

      rings = rings.filter((ring) => ring.alpha > 0.01);
      rings.forEach((ring) => {
        ring.radius += 8;
        ring.alpha *= 0.9;

        ctx.beginPath();
        ctx.strokeStyle = `rgba(147, 197, 253, ${ring.alpha})`;
        ctx.lineWidth = 2;
        ctx.arc(ring.x, ring.y, ring.radius, 0, Math.PI * 2);
        ctx.stroke();
      });

    }

    const handleResize = () => resizeCanvas();
    const handleClick = (event) => burstAt(event.clientX, event.clientY);

    resizeCanvas();
    animate();

    canvas.addEventListener("click", handleClick);
    window.addEventListener("resize", handleResize);

    return () => {
      canvas.removeEventListener("click", handleClick);
      window.removeEventListener("resize", handleResize);
      cancelAnimationFrame(animationFrame);
    };
  });
</script>

<style>
  .container {
    height: 100%;
    width: 100%;
    display: flex;
    justify-content: center;
    align-items: center;
    position: relative;
  }

  canvas {
    width: 100%;
    height: 100%;
    display: block;
    cursor: pointer;
  }
</style>

<div bind:this={container} class="container">
  <canvas bind:this={canvas} aria-label="WebLab particle animation"></canvas>
</div>
